import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";const o=JSON.parse(`{"title":"Installing Fabric on Linux","description":"A step-by-step guide on how to install Fabric on Linux.","frontmatter":{"title":"Installing Fabric on Linux","description":"A step-by-step guide on how to install Fabric on Linux.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"1.21.10/players/installing-fabric/linux.md","filePath":"versions/1.21.10/players/installing-fabric/linux.md","lastUpdated":1766682904000}`);var s={name:`1.21.10/players/installing-fabric/linux.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installing Fabric on Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Installing Fabric on Linux”">​</a></h1><div class="info custom-block"><p class="custom-block-title">PREREQUISITES</p><p>You may need to <a href="./../installing-java/linux">install Java</a> before running the <code>.jar</code>.</p></div><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Download the Fabric Installer <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Download the Fabric Installer”">​</a></h2><p>Download the <code>.jar</code> version of the Fabric Installer from the <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a>, by clicking on <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Run the Fabric Installer <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Run the Fabric Installer”">​</a></h2><p>Close Minecraft and the Minecraft Launcher first before running the installer.</p><p>Open a terminal and run the installer using Java:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer.jar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Once you open the installer, you should see a screen like this:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer with &quot;Install&quot; highlighted" loading="lazy"></p><p>Select your desired Minecraft version and click <code>Install</code>. Make sure that <code>Create Profile</code> is checked.</p><h2 id="3-finish-setup" tabindex="-1">3. Finish Setup <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Finish Setup”">​</a></h2><p>Once installation completes, open the Minecraft Launcher. Then select the Fabric profile from the version dropdown and click Play.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher with Fabric profile selected" loading="lazy"></p><p>You can now add mods to your game. See the <a href="./../finding-mods">Finding Trustworthy Mods</a> guide for info.</p><p>If you encounter issues, feel free to ask for help in the <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,16)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};